INSERT INTO public.software_projects (id, created_at, title_en, title_th, short_desc_en, short_desc_th, full_desc_en, full_desc_th, target_en, target_th, features_en, features_th, url, image_url, category, status, featured_slot) VALUES ('33333333-0000-0000-0000-000000000003', '2026-02-13 07:26:48.896809+00', 'Messaging Hub', 'ศูนย์กลางสื่อสาร', 'Unified communication platform for team messaging.', 'แพลตฟอร์มสื่อสารรวมศูนย์ เพื่อการส่งข้อความทีม', 'Messaging Hub serves as your organization''s central communication nerve center. This unified platform enables seamless team messaging, broadcast announcements, and targeted communication channels.', 'Messaging Hub คือศูนย์กลางการสื่อสารขององค์กร แพลตฟอร์มรวมศูนย์นี้ช่วยให้การส่งข้อความทีมและประกาศข่าวสารเป็นเรื่องง่าย', 'Medium to large enterprises
Educational institutions', '- องค์กรขนาดกลางถึงใหญ่
- สถาบันการศึกษา', 'Broadcast messaging to groups
Scheduled message delivery', '- ส่งข้อความบรอดแคสต์
- ตั้งเวลาส่งข้อความ', 'https://tagcast-connect.lovable.app', 'https://images.unsplash.com/photo-1611162617474-5b21e879e113?w=800&q=80', 'Web App', 'Active', 1);
INSERT INTO public.software_projects (id, created_at, title_en, title_th, short_desc_en, short_desc_th, full_desc_en, full_desc_th, target_en, target_th, features_en, features_th, url, image_url, category, status, featured_slot) VALUES ('33333333-0000-0000-0000-000000000001', '2026-02-13 07:26:48.896809+00', 'Check-in System', 'ระบบเช็คชื่อ', 'A streamlined check-in system for tracking attendance and achievements.', 'ระบบเช็คชื่อที่ทันสมัย สำหรับติดตามการเข้าเรียนและความสำเร็จแบบเรียลไทม์', 'Our Check-in System is a comprehensive solution designed for organizations to track attendance and monitor participant achievements in real-time. Built with modern web technologies, it offers a seamless experience for both administrators and users.', 'ระบบ Check-in System เป็นโซลูชันครบวงจรที่ออกแบบมาสำหรับองค์กรที่ต้องการติดตามการเข้าร่วมและตรวจสอบความสำเร็จของผู้เข้าร่วมแบบเรียลไทม์ สร้างด้วยเทคโนโลยีเว็บที่ทันสมัย', 'Corporate HR departments
Educational institutions
Event organizers', '- ฝ่ายทรัพยากรบุคคล
- สถาบันการศึกษา
- ผู้จัดงานอีเวนต์', 'Real-time attendance tracking
QR code check-in capability
Automated achievement badges', '- ติดตามการเข้าร่วมแบบเรียลไทม์
- เช็คอินด้วย QR Code
- ตราความสำเร็จอัตโนมัติ', 'https://check-it-ouch.lovable.app/', 'https://images.unsplash.com/photo-1531403009284-440f080d1e12?w=800&q=80', 'Web App', 'Active', 2);
INSERT INTO public.software_projects (id, created_at, title_en, title_th, short_desc_en, short_desc_th, full_desc_en, full_desc_th, target_en, target_th, features_en, features_th, url, image_url, category, status, featured_slot) VALUES ('33333333-0000-0000-0000-000000000002', '2026-02-13 07:26:48.896809+00', 'Freetime Matcher', 'ระบบจัดตารางเวลา', 'Intelligent scheduling tool for matching availability.', 'เครื่องมือจัดตารางเวลาอัจฉริยะ สำหรับจับคู่เวลาว่าง', 'Freetime Matcher revolutionizes the way teams coordinate their schedules. This intelligent scheduling tool analyzes team members'' availability and automatically suggests optimal meeting times.', 'Freetime Matcher ปฏิวัติการนัดหมายทีมด้วยการวิเคราะห์เวลาว่างและแนะนำเวลาประชุมที่เหมาะสมที่สุดโดยอัตโนมัติ บอกลาการส่งอีเมลไปมาเพื่อหาเวลาที่เหมาะสม', 'Remote and hybrid teams
Project managers
- HR coordinators', '- ทีมทำงานระยะไกล
- ผู้จัดการโครงการ
- ผู้ประสานงาน HR', 'Smart availability matching algorithm
Multi-timezone support
Calendar integration', '- อัลกอริทึมจับคู่เวลาอัจฉริยะ
- รองรับหลายเขตเวลา
- เชื่อมต่อปฏิทิน', 'https://ft-matcher.lovable.app/', 'https://images.unsplash.com/photo-1506784983877-45594efa4cbe?w=800&q=80', 'Web App', 'Active', 3);
